var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"죄송합니다, 인도자님. 물자를 공급하는 것이 쉽지 않아 마차 수리에는 시간이 걸릴 듯싶군요.","JPN":"申し訳ありません、導き手様。物資の供給が少ないので、馬車の修理に時間がかかりそうです。","ENG":"My apologies, Star Guide. With supply lines strained, the carriage repairs may take some time.","TWN":"抱歉，引導者大人。供應物資並不容易，修理馬車可能需要一些時間。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"수리 후 안전검사까지 마쳐야 하니 못해도 2주일은 필요합니다만…….","JPN":"修理後の安全点検までしないといけないですから、少なくとも2週間は必要ですが……","ENG":"After repairs, we'll also need to conduct a safety check. It'll take at least two weeks...","TWN":"修理後還需要進行安全檢查，至少需要兩周時間……"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"급히 출발해야 한다면 최대한 빠른 시일 내에 수리를 끝마치겠습니다.","JPN":"急いで出発する必要があるなら、なるべく早く修理を終わらせます。","ENG":"But if you need to leave urgently, I'll try to finish the work as quickly as possible.","TWN":"如果需要緊急出發，我會儘快完成修理。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"아뇨. 그러실 필요 없습니다.","JPN":"いいえ。その必要はありません。","ENG":"No, that won't be necessary.","TWN":"不，不必這樣。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전 괜찮으니 무리하지 말고 천천히 일하세요, 클링턴 씨.","JPN":"私は大丈夫ですのでごゆっくりどうぞ、クリントンさん。","ENG":"I'm fine, so don't push yourself. Take your time, Mr. Clinton.","TWN":"我沒關係，克林頓先生，請不要勉強，慢慢來吧。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……또 이곳에 계시는군요.","JPN":"……またここにいらしゃったのですか。","ENG":"...You're here again.","TWN":"……你又在這裡啊。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이곳에서 키우는 양들은 사납다고 전에 말씀드렸습니다만.","JPN":"ここで飼っている羊たちは、気が荒いとお伝えしたはずですが。","ENG":"If I recall, I warned you these sheep can be aggressive.","TWN":"我記得之前說過這裡養的羊很兇猛。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"사나운 양이래 봐야 괴수만은 못하지요.","JPN":"いくら気が荒くても怪獣よりは大人しいでしょう。","ENG":"Aggressive sheep are still nothing compared to monsters.","TWN":"再兇猛的羊也比不上怪獸。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"시야가 트여 마을을 둘러보기 또한 안성맞춤이니, 이만한 장소를 찾기 어렵겠습니다.","JPN":"視界が開けていますので、村を見渡すのにここ以上の場所はありません。","ENG":"The open view makes it a perfect place to look over the village. It's hard to find a better spot.","TWN":"視野開闊，環顧村莊也是絕佳之選，這樣的地方很難找到。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전 신경 쓰지 마시고, 부디.","JPN":"私のことはお構いなく。","ENG":"Please, pay me no mind.","TWN":"請不要在意，務必如此。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……예, 알겠습니다.","JPN":"……はい、かしこまりました。","ENG":"...Understood.","TWN":"……是，明白。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"귀족에게 잘 보이려는 사람들과는 달리 그는 내게 별다른 말은 하지 않았다.","JPN":"貴族に良い印象を与えようとする人々とは違い、彼は私にあまり話しかけることはなかった。","ENG":"Unlike those who tried to curry favor with nobles, he never said much to me.","TWN":"與那些想討好貴族的人不同，他對我沒有多說什麼。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"거리를 유지한 채, 이따금씩 내 상태를 확인하려 할 뿐.","JPN":"距離を取ったまま、たまに私の様子を確認するだけ。","ENG":"He kept his distance, only occasionally checking in.","TWN":"保持距離，只是偶爾想確認我的狀態而已。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"양과 사투하는 그를 바라보는 건 썩 나쁘지 않은 광경이었다.","JPN":"羊と格闘している彼を見るのは、なかなか悪くない光景だった。","ENG":"Watching him wrestle with the sheep wasn't a bad sight.","TWN":"看著他與羊搏鬥的場景，倒也不算太糟糕。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"다른 목동들은 목양견을 함께 사육하던데, 이곳에는 그런 동물이 보이지 않는군요.","JPN":"他の羊飼いは牧羊犬を一緒に飼っているのに、ここにはそのような動物は見当たりませんね。","ENG":"Other shepherds usually keep sheepdogs. I don't see any here.","TWN":"其他牧童都和牧羊犬一起飼養，但這裡似乎沒有看到這樣的動物。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"최소한의 검술은 익혔으니, 짐승들로부터 가축을 지키는 것은 어려운 일이 아닙니다.","JPN":"最低限の剣術は身につけているので、獣から家畜を守ることは難しくありません。","ENG":"I've learned the basics of swordsmanship. Protecting livestock from beasts isn't that difficult.","TWN":"至少掌握了基本的劍術，保護牲畜免受野獸侵害並不困難。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"검술에 능한 제 친척 역시 마을을 지키기 위해 힘을 보태고 있고요.","JPN":"剣術の腕がある私の親戚もまた、村を守るために頑張っています。","ENG":"One of my relatives, who's more skilled with the sword, helps protect the village as well.","TWN":"我擅長劍術的親戚也在為守護村莊貢獻力量。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게, 하루가 지나고.","JPN":"そうして、一日が過ぎ。","ENG":"And so, another day passed.","TWN":"就這樣，一天過去了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"분명 위험하다 말하지 않았습니까.","JPN":"確かに危険だと言ったはずです。","ENG":"I told you it was dangerous.","TWN":"你不是說過很危險嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제가 한눈을 팔았더라면, 영애 분의 귀한 몸에 상처가 났을 겁니다.","JPN":"私がよそ見をしていたら、ご令嬢はお怪我をされていたことでしょう。","ENG":"If I'd let my guard down, you might've gotten hurt.","TWN":"如果我一時疏忽，小姐你尊貴的身體就會受傷。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 한 몸 지킬 여력은 충분하니 걱정하실 필요 없습니다.","JPN":"自分の身を守る力は十分ありますので、心配しないでください。","ENG":"I'm more than capable of protecting myself. You don't have to worry.","TWN":"我有足夠的能力保護自己，不用擔心。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그래도 혹여 걱정되신다면… 그래요.","JPN":"それでも心配だと言うなら……そうですね。","ENG":"But if you're that concerned... All right.","TWN":"不過如果你還是擔心的話……也是可以的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당신의 검을, 제가 잠시 손볼 수 있을까요?","JPN":"よろしければ、貴方の剣を少々見せてもらってもいいですか？","ENG":"May I take a look at your sword?","TWN":"你的劍，我可以稍微處理一下嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제 검을 말입니까?","JPN":"私の剣を、ですか？","ENG":"My sword?","TWN":"我的劍嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"영리한 짐승은 발톱을 내민 포식자 앞에서 제 몸을 사리는 법이지요.","JPN":"賢い獣は爪をむきだした捕食者の前では慎重になるものです。","ENG":"Smart animals know to keep their distance when they sense a predator's claws.","TWN":"聰明的野獸在露出爪子的掠食者面前懂得保護自己。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};